import { signInWithEmailAndPassword, createUserWithEmailAndPassword, signOut, onAuthStateChanged } from 'firebase/auth';
import { doc, getDoc, setDoc, collection, getDocs } from 'firebase/firestore';
import { auth, db } from '../firebase';
import { ROLES } from '../utils/permissions';

class AuthService {
  constructor() {
    this.currentUser = null;
    this.currentCompany = null;
    this.listeners = [];
  }

  // Iniciar sesión
  async login(email, password) {
    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, password);
      const user = userCredential.user;

      // Obtener información del usuario desde Firestore
      const userDoc = await getDoc(doc(db, 'users', user.uid));
      const userData = userDoc.data();

      if (!userData) {
        throw new Error('Usuario no encontrado en la base de datos');
      }

      // Si es Super Admin, no necesita compañía
      if (userData.role === ROLES.SUPER_ADMIN) {
        this.currentUser = { ...user, ...userData };
        this.currentCompany = null;

        console.log('👑 Super Admin autenticado:', this.currentUser);
        this.notifyListeners();
        return { user: this.currentUser, company: null };
      }

      // Para otros roles, obtener información de la compañía
      const companyDoc = await getDoc(doc(db, 'companies', userData.companyId));
      const companyData = companyDoc.data();

      if (!companyData) {
        throw new Error('Compañía no encontrada');
      }

      this.currentUser = { ...user, ...userData };
      this.currentCompany = companyData;

      console.log('🔥 Usuario autenticado:', this.currentUser);
      console.log('🏢 Compañía seleccionada:', this.currentCompany);

      // Notificar a los listeners
      this.notifyListeners();

      return { user: this.currentUser, company: this.currentCompany };
    } catch (error) {
      console.error('❌ Error en login:', error);
      throw error;
    }
  }

  // Crear usuario (solo para Super Admin)
  async createUser(userData, companyId, role) {
    try {
      if (!this.isSuperAdmin()) {
        throw new Error('Solo el Super Admin puede crear usuarios');
      }

      // Crear usuario en Firebase Auth
      const userCredential = await createUserWithEmailAndPassword(
        auth, 
        userData.email, 
        userData.password
      );
      const user = userCredential.user;

      // Crear usuario en Firestore
      const userRef = doc(db, 'users', user.uid);
      await setDoc(userRef, {
        ...userData,
        id: user.uid,
        companyId: companyId,
        role: role,
        createdBy: this.currentUser.id,
        createdAt: new Date().toISOString(),
        isActive: true
      });

      console.log('✅ Usuario creado por Super Admin:', user.uid);

      return { success: true, userId: user.uid };
    } catch (error) {
      console.error('❌ Error al crear usuario:', error);
      throw error;
    }
  }

  // Crear compañía (solo para Super Admin)
  async createCompany(companyData) {
    try {
      if (!this.isSuperAdmin()) {
        throw new Error('Solo el Super Admin puede crear compañías');
      }

      const companyRef = doc(collection(db, 'companies'));
      const companyId = companyRef.id;

      await setDoc(companyRef, {
        ...companyData,
        id: companyId,
        createdBy: this.currentUser.id,
        createdAt: new Date().toISOString(),
        isActive: true
      });

      console.log('✅ Compañía creada por Super Admin:', companyId);

      return { success: true, companyId };
    } catch (error) {
      console.error('❌ Error al crear compañía:', error);
      throw error;
    }
  }

  // Obtener todas las compañías (solo Super Admin)
  async getAllCompanies() {
    try {
      if (!this.isSuperAdmin()) {
        throw new Error('Acceso denegado');
      }

      const querySnapshot = await getDocs(collection(db, 'companies'));
      const companies = querySnapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      }));

      return companies;
    } catch (error) {
      console.error('❌ Error al obtener compañías:', error);
      throw error;
    }
  }

  // Obtener usuarios de una compañía (solo Super Admin y Company Admin)
  async getCompanyUsers(companyId) {
    try {
      if (!this.canManageUsers(companyId)) {
        throw new Error('Acceso denegado');
      }

      const querySnapshot = await getDocs(collection(db, 'users'));
      const users = querySnapshot.docs
        .map(doc => ({ id: doc.id, ...doc.data() }))
        .filter(user => user.companyId === companyId);

      return users;
    } catch (error) {
      console.error('❌ Error al obtener usuarios:', error);
      throw error;
    }
  }

  // Verificar si es Super Admin
  isSuperAdmin() {
    return this.currentUser?.role === ROLES.SUPER_ADMIN;
  }

  // Verificar si puede gestionar usuarios de una compañía
  canManageUsers(companyId) {
    return this.isSuperAdmin() || 
           (this.currentUser?.role === ROLES.COMPANY_ADMIN && this.currentUser?.companyId === companyId);
  }

  // Cerrar sesión
  async logout() {
    try {
      await signOut(auth);
      this.currentUser = null;
      this.currentCompany = null;
      this.notifyListeners();
      console.log('👋 Sesión cerrada');
    } catch (error) {
      console.error('❌ Error al cerrar sesión:', error);
      throw error;
    }
  }

  // Observador de estado de autenticación
  onAuthStateChanged(callback) {
    this.listeners.push(callback);

    const unsubscribe = onAuthStateChanged(auth, async (user) => {
      if (user) {
        try {
          const userDoc = await getDoc(doc(db, 'users', user.uid));
          const userData = userDoc.data();

          if (userData) {
            if (userData.role === ROLES.SUPER_ADMIN) {
              this.currentUser = { ...user, ...userData };
              this.currentCompany = null;
            } else {
              const companyDoc = await getDoc(doc(db, 'companies', userData.companyId));
              const companyData = companyDoc.data();

              this.currentUser = { ...user, ...userData };
              this.currentCompany = companyData;
            }
          }
        } catch (error) {
          console.error('Error al cargar datos del usuario:', error);
        }
      } else {
        this.currentUser = null;
        this.currentCompany = null;
      }

      callback({ user: this.currentUser, company: this.currentCompany });
    });

    return unsubscribe;
  }

  // Notificar a todos los listeners
  notifyListeners() {
    this.listeners.forEach(callback => {
      callback({ user: this.currentUser, company: this.currentCompany });
    });
  }

  // Getters
  getUser() {
    return this.currentUser;
  }

  getCompany() {
    return this.currentCompany;
  }

  isAuthenticated() {
    return this.currentUser !== null;
  }

  hasRole(role) {
    return this.currentUser?.role === role;
  }

  // Obtener rol del usuario actual
  getRole() {
    return this.currentUser?.role || null;
  }
}

const authService = new AuthService();
export default authService;
